class Solution:
    def areOccurrencesEqual(self, s):
        from collections import Counter
        c = Counter(s)
        vals = list(c.values())
        for v in vals:
            if v != vals[0]:
                return False
        return True

solutions.python:
class Solution:
    def areOccurrencesEqual(self, s):
        from collections import Counter
        return len(set(Counter(s).values())) == 1

